function extractMentions(text) {
  const matches = text.match(/\b([A-Z][a-z]+(?: [A-Z][a-z]+){1,3})\b/g) || [];
  return [...new Set(matches)].slice(0, 4);
}

// Bayesian confidence: source_credibility * recency_decay
// corroboration_factor starts at 1.0 (graph will update as more sources confirm)
function computeConfidence(sourceCred, pubDate) {
  const now = Date.now();
  const pub = pubDate ? new Date(pubDate).getTime() : now;
  const ageHours = Math.max(0, (now - pub) / 3600000);
  const recencyDecay = Math.exp(-0.02 * ageHours); // half-life ~35 hours
  return Math.round(sourceCred * recencyDecay * 100) / 100;
}

for (const item of items) {
  const a = item.json;
  if (!a || typeof a !== 'object' || !a.title || !a.source) continue;

  const title = String(a.title).trim().substring(0, 200);
  const category = a.category || 'world_news';
  const source = a.source;
