      targetName: mention,
      targetType: 'person',
      relation: 'related_to',
      confidence: 0.4,
      causal_weight: causal_weight * 0.5,
      mechanism
    });
  }

  results.push({ json: {
    name: title,
    type: entityType,
    properties: {
      url,
      description: description.substring(0, 500),
      category,
      published,
      source_credibility,
