const STOP_WORDS = new Set(['The','A','An','In','On','At','By','To','Of','For','And','But','Or','If','As','With','From','That','This','These','Those','Its','His','Her','Their','Our','We','He','She','They','It','I','You','Mr','Ms','Dr','Prof','said','says','told','according']);

function extractEntities(text) {
  const matches = text.match(/\b([A-Z][a-zA-Z'-]+(?:\s+[A-Z][a-zA-Z'-]+){0,4})\b/g) || [];
  return [...new Set(matches.map(m => m.trim()).filter(m => m.length > 2 && !STOP_WORDS.has(m.split(' ')[0])))].slice(0, 6);
}

function sentences(text) {
  return text.replace(/([.!?])\s+/g, '$1\n').split('\n').map(s => s.trim()).filter(s => s.length > 20);
}

function mechanismFrom(trigger) {
  const t = trigger.toLowerCase();
  if (/caus|forc|trigger/.test(t)) return 'direct_causation';
  if (/leads?\s+to|results?\s+in|contributes?/.test(t)) return 'causal_chain';
  if (/fuel|boost|accelerat/.test(t)) return 'amplification';
  if (/weaken|damage|worsen|lower|decreas/.test(t)) return 'degradation';
  if (/spread|spill|ripple/.test(t)) return 'contagion';
  if (/response|following|after|due\s+to|owing/.test(t)) return 'reactive_response';
  return 'causal_association';
}

function extractCausalTriples(text) {
  const triples = [];
  const seen = new Set();
  for (const sent of sentences(text)) {
    for (const trigger of CAUSAL_TRIGGERS) {
      const match = trigger.re.exec(sent);
      if (!match) continue;
      const before = sent.substring(0, match.index).trim();
      const after = sent.substring(match.index + match[0].length).trim();
      if (before.length < 3 || after.length < 3) continue;
      const causeEntities = extractEntities(before);
      const effectEntities = extractEntities(after);
      if (!causeEntities.length || !effectEntities.length) continue;
      const cause = causeEntities[causeEntities.length - 1];
      const effect = effectEntities[0];
      if (cause === effect) continue;
      const key = cause + '|' + effect;
      if (seen.has(key)) continue;
      seen.add(key);
      triples.push({ cause, effect, attribution_type: trigger.type, causal_weight: trigger.weight, mechanism: mechanismFrom(match[0]), evidence_span: sent.substring(0, 250) });
      if (triples.length >= 5) break;
    }
    if (triples.length >= 5) break;
  }
  return triples;
}

