async function resolveQID(name) {
  if (!name || name.length < 3) return null;
  try {
    const encoded = encodeURIComponent(name);
    const url = `https://www.wikidata.org/w/api.php?action=wbsearchentities&search=${encoded}&language=en&limit=1&format=json&origin=*`;
    const resp = await $http.request({ method: 'GET', url });
    const hits = resp.search;
    if (hits && hits.length > 0) return hits[0].id; // e.g. "Q312"
    return null;
  } catch (e) {
    return null;
  }
}

for (const item of items) {
  const a = item.json;
  if (!a || typeof a !== 'object' || a._empty) {
    results.push(item);
    continue;
  }

  // Only resolve for high-confidence, named entities worth grounding
  if (a.confidence >= 0.5 && a.name && a.name.length > 3 && a.name !== 'empty') {
    const qid = await resolveQID(a.name);
    if (qid) {
      results.push({ json: {
        ...a,
        properties: { ...a.properties, wikidata_qid: qid }
      }});
      continue;
    }
  }
  results.push(item);
}

